fix:
import java.lang.reflect.ParameterizedType;
import java.lang.reflect.Type;

public class RepairedReadTypeVariablesMethod {

    private Type[] typesArrayCache;

    private void readTypeVariables(){

          //if there's no bounds on type variables, break directly 
           if(typeVariable.getBounds().length == 0){
               return ;
           }

         typesArrayCache = new Type[typeVariable.getBounds().length];  

         int i = 0;

         //loop through all bound types
         for (Type t : typeVariable.getBounds()){

             if(t instanceof ParameterizedType){
                 ParameterizedType pt = (ParameterizedType) t;                 
                 //recursive call here to solve nested generic problem
                 readTypeVariables((TypeVariable<?>) pt.getActualTypeArguments()[i]);                    
             } else{                     
                 typesArrayCache[i] = t; 
                i++;                 
             }
        }     
    }

    /**
     * Recursive function to handle nested generic problems
     */
    private void readTypeVariables(TypeVariable<?> tv){ 

        typeVariable = tv;        

        if(tv == null || !typesByName.containsKey(tv.getName())){
            return;
        }        

        List<Type> listTypes = typesByName.remove(tv.getName());        

        Set<Type> setTypes = new LinkedHashSet<>();
        for(Type eachType: listTypes){            
            addSupertypeToListIfNotPresentAlready(eachType,setTypes);
        }        
        listTypes = new ArrayList<>(setTypes);

        Class<?> rawType = getUpperBoundedWildcardTypeOr(tv);         
        if(!listTypes.isEmpty() && !rawType.equals(Object.class)){
            throw new UnsupportedOperationException(tv + " is both upper bounded wild card ("+rawType +") but have more than one direct or transitive super-types " + listTypes);
        } else if(!listTypes.isEmpty()){
            setTypesFromSupertypesWithMoreThanOneDirectOrTransitives(tv , listTypes);
        } else if(rawType!= Object.class){
            setSuperInterfaceTypesFromClassesLowerBoundTo(tv, rawType );
        }else{
            rawExtraInterfaces.addAll(listTypes);
        }
        rawType = tv.getBounds()[0].getClass();  
        if(rawType.isAssignableFrom(getUpperBoundedWildcardTypeOr(tv))){
            throw new RuntimeException("bounding too tight:" + tv  +" -- lower bounded to:"+rawType);
        }else if (!tv.getBounds()[0].equals(listTypes.get(0).getClass())){
            throw new UnsupportedOperationException("Conflicting bounds on type parameter: " + tv + 
                                                   " bounds: [" + Arrays.toString(tv.getBounds()) + "]"+
                                                    " raw argument: " + tv.getGenericDeclaration());
        }

    }  
}

issue_description:
Deep stubbing will throw an Exception if multiple generics occur in the call chain. For instance, consider having a mock myMock1 that provides a function that returns a generic T. If T also has a function that returns a generic, an Exception with the message "Raw extraction not supported for : 'null'" will be thrown.
As an example the following test will throw an Exception:
public class MockitoGenericsDeepStubTest {

    @Test
    public void discoverDeepMockingOfGenerics() {
        MyClass1 myMock1 = mock(MyClass1.class, RETURNS_DEEP_STUBS);

        when(myMock1.getNested().getNested().returnSomething()).thenReturn("Hello World.");
    }

    public static interface MyClass1 <MC2 extends MyClass2> {
        public MC2 getNested();
    }

    public static interface MyClass2<MC3 extends MyClass3> {
        public MC3 getNested();
    }

    public static interface MyClass3 {
        public String returnSomething();
    }
}
You can make this test run if you step into the class ReturnsDeepStubs and change the method withSettingsUsing to return MockSettings with ReturnsDeepStubs instead of ReturnsDeepStubsSerializationFallback as default answer:
private MockSettings withSettingsUsing(GenericMetadataSupport returnTypeGenericMetadata, MockCreationSettings parentMockSettings) {
    MockSettings mockSettings = returnTypeGenericMetadata.hasRawExtraInterfaces() ?
            withSettings().extraInterfaces(returnTypeGenericMetadata.rawExtraInterfaces())
            : withSettings();

    return propagateSerializationSettings(mockSettings, parentMockSettings)
            .defaultAnswer(this);
}
However, this breaks other tests and features.
I think, the issue is that further generics are not possible to be mocked by ReturnsDeepStubsSerializationFallback since the GenericMetadataSupport is "closed" at this point.
Thanks and kind regards
Tobias

